# ─── 配置读写 ─────────────────────────────────────────────────────────────────

async def get_config() -> dict:
    """读取分类引擎配置，不存在则返回默认值。"""
    async with get_async_session_local() as db:
        row = await db.execute(
            select(SystemConfig).where(SystemConfig.key == _CONFIG_KEY)
        )
        cfg = row.scalars().first()
        if cfg and cfg.value:
            try:
                saved = json.loads(cfg.value)
                # 向后兼容：旧 p115_organize_config 的 dict 格式自动迁移
                if isinstance(saved.get("categories"), dict):
                    saved["categories"] = [
                        {"name": k, "target_dir": v, "match_all": False, "rules": []}
                        for k, v in saved["categories"].items()
                    ]
                return {**_DEFAULT_CONFIG, **saved}
            except Exception:
                pass
    return dict(_DEFAULT_CONFIG)


async def save_config(config: dict) -> bool:
    """保存分类引擎配置。"""
    from src.core.timezone import tm
    async with get_async_session_local() as db:
        row = await db.execute(
            select(SystemConfig).where(SystemConfig.key == _CONFIG_KEY)
        )
        cfg = row.scalars().first()
        value = json.dumps(config, ensure_ascii=False)
        if cfg:
            cfg.value = value
            cfg.updated_at = tm.now()
        else:
            cfg = SystemConfig(
                key=_CONFIG_KEY,
                value=value,
                description="通用整理分类引擎配置",
            )
            db.add(cfg)
        await db.commit()
    logger.info("[分类引擎] 配置已保存，共 %d 个分类", len(config.get("categories", [])))
    return True


# ─── 规则匹配核心 ─────────────────────────────────────────────────────────────

def _match_rule(rule: dict, filename: str, dirname: str, tmdb: dict) -> bool:
    """执行单条规则匹配。"""
    rtype = rule.get("type", "keyword")
    value = rule.get("value", "").strip()
    if not value:
        return False

    # TMDB 字段匹配
    if rtype == "genre_ids":
        want = {int(v.strip()) for v in value.split(",") if v.strip().isdigit()}
        have = {int(g) for g in tmdb.get("genre_ids", []) if str(g).isdigit()}
        return bool(want & have)

    if rtype == "origin_country":
        want = {v.strip().upper() for v in value.split(",")}
        have = {c.upper() for c in tmdb.get("origin_country", [])}
        return bool(want & have)

    if rtype == "original_language":
        want = {v.strip().lower() for v in value.split(",")}
        return tmdb.get("original_language", "").lower() in want

    # 本地文件名匹配
    field = rule.get("field", "filename")
    text = filename if field == "filename" else dirname
    try:
        if rtype == "regex":
            return bool(re.search(value, text))
        return value.lower() in text.lower()   # keyword
    except Exception:
        return False


def detect_category(
    filename: str,
    dirname: str,
    tmdb_info: dict,
    categories: list,
) -> Optional[str]:
    """
    对单个文件执行分类规则匹配。

    Args:
        filename:   文件名（含扩展名）
        dirname:    所在目录名
        tmdb_info:  TMDB 元数据 dict（可为空 {}）
        categories: 分类规则列表（来自 get_config()["categories"]）

    Returns:
        命中的分类名；如果有兜底分类则返回兜底名；否则返回 None。
    """
    fallback: Optional[str] = None
    for cat in categories:
        name  = cat.get("name", "")
        rules = cat.get("rules", [])
        if not name:
            continue
        if not rules:
            fallback = name   # 无规则 → 兜底
            continue
        match_all = cat.get("match_all", False)
        if match_all:
            matched = all(_match_rule(r, filename, dirname, tmdb_info) for r in rules)
        else:
            matched = any(_match_rule(r, filename, dirname, tmdb_info) for r in rules)
        if matched:
            return name
    return fallback


# ─── TMDB 元数据查询（带内存缓存）───────────────────────────────────────────

_tmdb_cache: dict = {}


async def _get_tmdb_provider():
    """从 SystemConfig 读取 TMDB 配置，返回 TMDBProvider；未配置则返回 None。"""
    try:
        async with get_async_session_local() as db:
            row = await db.execute(
                select(SystemConfig).where(SystemConfig.key == "metadata_tmdb")
            )
            cfg = row.scalars().first()
            if not cfg or not cfg.value:
                return None
            data = json.loads(cfg.value)
            api_key = data.get("api_key", "").strip()
            if not api_key:
                return None
            from src.adapters.metadata.tmdb import TMDBProvider
            return TMDBProvider(api_key=api_key, language=data.get("language", "zh-CN"))
    except Exception as e:
        logger.debug("[分类引擎] 获取 TMDB 配置失败: %s", e)
        return None


async def fetch_tmdb_info(title: str, is_movie: bool, year: Optional[str] = None) -> dict:
    """
    查询 TMDB 并返回 {genre_ids, origin_country, original_language}。
    结果带内存缓存（进程级），key = title|movie/tv。
    """
    cache_key = f"{title}|{'movie' if is_movie else 'tv'}"
    if cache_key in _tmdb_cache:
        return _tmdb_cache[cache_key]

    result: dict = {}
    tmdb = await _get_tmdb_provider()
    if tmdb is None:
        return result

    try:
        media_type = "movie" if is_movie else "tv"
        year_int   = int(year) if year and str(year).isdigit() else 0
        results    = await tmdb.search(title, media_type=media_type, year=year_int)
        if not results and year_int:
            results = await tmdb.search(title, media_type=media_type)
        if results:
            top     = results[0]
            tmdb_id = top.extra.get("id") or top.tmdb_id
            if tmdb_id:
                detail = await tmdb.get_detail(int(tmdb_id), media_type=media_type)
                if detail:
                    result = {
                        "genre_ids":         top.extra.get("genre_ids", []),
                        "origin_country":    detail.extra.get("origin_country", []),
                        "original_language": detail.extra.get("original_language", ""),
                    }
    except Exception as e:
        logger.warning("[分类引擎] TMDB 查询失败 title=%s: %s", title, e)

    _tmdb_cache[cache_key] = result
    return result


async def is_tmdb_available() -> bool:
    """检测 TMDB API Key 是否已配置可用。"""
    return (await _get_tmdb_provider()) is not None

