// 通用整理分类模块 — 独立页面
// 职责：管理分类规则配置，不绑定任何具体平台（115/本地等）
// 其他模块触发整理时读取此配置进行分类。

import { useEffect, useState, useRef, useCallback } from 'react'
import {
  Card, Row, Col, Form, Input, Switch, Button, Select, Tag, Space,
  Alert, Tooltip, Divider, message, Segmented, Badge, Typography,
