import { classifyApi } from '@/apis'
import DirPickerModal from '@/components/DirPickerModal'

const { Text } = Typography
const { TextArea } = Input

// 分类卡片颜色序列
const CAT_COLORS = ['blue','purple','green','orange','red','cyan','volcano','gold','lime','magenta']

// 规则类型选项
const RULE_TYPE_OPTIONS = [
  { value: 'keyword',           label: '关键词' },
  { value: 'regex',             label: '正则' },
  { value: 'genre_ids',         label: 'TMDB类型ID' },
  { value: 'origin_country',    label: 'TMDB产地' },
  { value: 'original_language', label: 'TMDB语言' },
]
const TMDB_TYPES = ['genre_ids', 'origin_country', 'original_language']

const RULE_HINTS = {
  genre_ids:         'TMDB genre_id，多个逗号分隔，如 16（动画）、99（纪录片）',
  origin_country:    '国家代码，多个逗号分隔，如 JP 或 CN,TW,HK',
  original_language: 'TMDB original_language，如 zh、ja、en',
  keyword:           '文件名/目录名中包含的关键词',
  regex:             '正则表达式，如 (?i)(anime|OVA)',
}

const DEFAULT_CONFIG = {
  enabled: true,
  dry_run: false,
  target_root: '',
  unrecognized_dir: '',
  categories: [],
}

// ─── 单个分类卡片 ──────────────────────────────────────────────────────────────
const CategoryCard = ({ cat, catIdx, total, onUpdate, onDelete, onMove, color }) => {
  const isDefault = !cat.rules || cat.rules.length === 0

  const updateRule = (rIdx, patch) =>
    onUpdate({ rules: cat.rules.map((r, i) => i === rIdx ? { ...r, ...patch } : r) })
  const addRule = () =>
    onUpdate({ rules: [...(cat.rules || []), { type: 'keyword', field: 'filename', value: '' }] })
  const delRule = (rIdx) =>
    onUpdate({ rules: cat.rules.filter((_, i) => i !== rIdx) })

  return (
    <div style={{
      border: '1px solid var(--ant-color-border, #d9d9d9)',
      borderLeft: `4px solid var(--ant-color-${color}-6, #1677ff)`,
      borderRadius: 8, marginBottom: 12, background: 'var(--ant-color-bg-container,#fff)',
      overflow: 'hidden',
    }}>
      {/* 卡片头 */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8, padding: '8px 12px',
        background: 'var(--ant-color-fill-quaternary, rgba(0,0,0,.04))',
        borderBottom: '1px solid var(--ant-color-border-secondary, #f0f0f0)',
      }}>
        <span style={{
          width: 22, height: 22, borderRadius: '50%', flexShrink: 0,
          background: `var(--ant-color-${color}-6, #1677ff)`, color: '#fff',
          display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, fontWeight: 700,
        }}>{catIdx + 1}</span>

        <Input
          size="small" variant="borderless"
          value={cat.name} placeholder="分类名称"
          style={{ fontWeight: 600, flex: 1, maxWidth: 140 }}
          onChange={e => onUpdate({ name: e.target.value })}
        />
        <Text type="secondary" style={{ fontSize: 12 }}>→</Text>
        <Input
          size="small" variant="borderless"
          value={cat.target_dir} placeholder="目标子目录"
          style={{ flex: 1, maxWidth: 160, fontSize: 12 }}
          onChange={e => onUpdate({ target_dir: e.target.value })}
        />

        {isDefault && <Tag color="orange" style={{ fontSize: 11, margin: 0 }}>默认兜底</Tag>}

        <Space size={2} style={{ flexShrink: 0 }}>
          <Tooltip title="上移"><Button size="small" icon={<ArrowUpOutlined />} disabled={catIdx === 0}
            onClick={() => onMove(-1)} /></Tooltip>
          <Tooltip title="下移"><Button size="small" icon={<ArrowDownOutlined />} disabled={catIdx === total - 1}
            onClick={() => onMove(1)} /></Tooltip>
          <Tooltip title="删除分类"><Button size="small" danger icon={<DeleteOutlined />} onClick={onDelete} /></Tooltip>
        </Space>
      </div>

      {/* 规则区域 */}
      <div style={{ padding: '10px 12px' }}>
        {/* 匹配逻辑 */}
        {cat.rules?.length > 1 && (
          <div style={{ marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
            <Text type="secondary" style={{ fontSize: 12 }}>匹配逻辑：</Text>
            <Switch size="small" checked={cat.match_all}
              checkedChildren="AND 全部" unCheckedChildren="OR 任一"
              onChange={v => onUpdate({ match_all: v })} />
          </div>
        )}

        {isDefault
          ? <Text type="secondary" style={{ fontSize: 12, fontStyle: 'italic' }}>
              无匹配规则 — 作为兜底分类（未命中其他分类的文件归入此处）
            </Text>
          : (cat.rules || []).map((rule, rIdx) => {
            const isTmdb = TMDB_TYPES.includes(rule.type)
            return (
              <Row key={rIdx} gutter={4} style={{ marginBottom: 6 }} align="middle" wrap={false}>
                <Col style={{ width: 110, flexShrink: 0 }}>
                  <Select size="small" style={{ width: '100%' }} value={rule.type}
                    options={RULE_TYPE_OPTIONS}
                    onChange={v => updateRule(rIdx, {
                      type: v,
                      field: TMDB_TYPES.includes(v) ? undefined : (rule.field || 'filename'),
                    })} />
                </Col>
                {!isTmdb && (
                  <Col style={{ width: 76, flexShrink: 0 }}>
                    <Select size="small" style={{ width: '100%' }} value={rule.field || 'filename'}
                      options={[{ value: 'filename', label: '文件名' }, { value: 'dirname', label: '目录名' }]}
                      onChange={v => updateRule(rIdx, { field: v })} />
                  </Col>
                )}
                <Col flex="1">
                  <Tooltip title={RULE_HINTS[rule.type]}>
                    <Input size="small" value={rule.value}
                      placeholder={RULE_HINTS[rule.type] || '输入匹配值'}
                      onChange={e => updateRule(rIdx, { value: e.target.value })} />
                  </Tooltip>
                </Col>
                <Col>
                  <Button danger size="small" icon={<DeleteOutlined />} onClick={() => delRule(rIdx)} />
                </Col>
              </Row>
            )
          })
        }

        <Button size="small" icon={<PlusOutlined />} onClick={addRule}
          style={{ marginTop: isDefault ? 0 : 4 }}>
          添加规则
        </Button>
      </div>
    </div>
  )
}

// ─── 代码编辑模式 ──────────────────────────────────────────────────────────────
const CodeEditor = ({ value, onChange }) => {
  const [err, setErr] = useState('')
  const handleChange = (v) => {
    onChange(v)
    try { JSON.parse(v); setErr('') } catch (e) { setErr(e.message) }
  }
  return (
    <div>
      <Alert type="info" showIcon style={{ marginBottom: 8 }}
        message="直接编辑 JSON 配置，保存时将覆盖图形化设置。修改后切换到图形化模式可预览效果。" />
      {err && <Alert type="error" message={`JSON 格式错误: ${err}`} style={{ marginBottom: 8 }} />}
      <TextArea
        value={value} rows={20} spellCheck={false}
        onChange={e => handleChange(e.target.value)}
        style={{
          fontFamily: "'Cascadia Code','Fira Code',monospace", fontSize: 12,
          lineHeight: 1.6, resize: 'vertical',
          background: 'var(--ant-color-bg-container,#fff)',
        }}
      />
    </div>
  )
}

// ─── 主页面 ────────────────────────────────────────────────────────────────────
export const Classify = () => {
  const [cfg, setCfg]               = useState(DEFAULT_CONFIG)
  const [editMode, setEditMode]     = useState('gui')   // 'gui' | 'code'
  const [codeText, setCodeText]     = useState('')
  const [saving, setSaving]         = useState(false)
  const [tmdbOk, setTmdbOk]         = useState(null)
  const [dirPickerOpen, setDirPickerOpen]   = useState(false)
  const [dirPickerTarget, setDirPickerTarget] = useState(null)

  // ── 数据加载 ──────────────────────────────────────────────────────────────
  const load = useCallback(async () => {
    try {
      const [cfgRes, tmdbRes] = await Promise.all([
        classifyApi.getConfig(),
        classifyApi.getTmdbStatus(),
      ])
      const data = cfgRes.data || DEFAULT_CONFIG
      setCfg(data)
      setCodeText(JSON.stringify(data, null, 2))
      setTmdbOk(!!tmdbRes.data?.available)
    } catch { message.error('加载分类配置失败') }
  }, [])

  useEffect(() => { load() }, [load])

  // ── GUI <-> 代码 切换 ──────────────────────────────────────────────────────
  const handleModeChange = (mode) => {
    if (mode === 'code') {
      // 切换到代码模式：把当前 GUI 状态序列化
      setCodeText(JSON.stringify(cfg, null, 2))
    } else {
      // 切换回 GUI 模式：尝试解析代码模式的文本
      try {
        setCfg(JSON.parse(codeText))
      } catch {
        message.warning('JSON 格式错误，保留当前图形化状态')
      }
    }
    setEditMode(mode)
  }

  // ── 保存 ──────────────────────────────────────────────────────────────────
  const handleSave = async () => {
    let payload = cfg
    if (editMode === 'code') {
      try { payload = JSON.parse(codeText) }
      catch { message.error('JSON 格式错误，无法保存'); return }
    }
    setSaving(true)
    try {
      await classifyApi.saveConfig(payload)
      setCfg(payload)
      setCodeText(JSON.stringify(payload, null, 2))
      message.success('分类配置已保存')
    } catch { message.error('保存失败') }
    finally { setSaving(false) }
  }

  // ── 分类操作 ──────────────────────────────────────────────────────────────
  const updateCat = (idx, patch) =>
    setCfg(c => ({ ...c, categories: c.categories.map((v, i) => i === idx ? { ...v, ...patch } : v) }))
  const deleteCat = (idx) =>
    setCfg(c => ({ ...c, categories: c.categories.filter((_, i) => i !== idx) }))
  const moveCat = (idx, dir) =>
    setCfg(c => {
      const arr = [...c.categories]
      ;[arr[idx], arr[idx + dir]] = [arr[idx + dir], arr[idx]]
      return { ...c, categories: arr }
    })
  const addCat = () =>
    setCfg(c => ({
      ...c,
      categories: [...c.categories, { name: '', target_dir: '', match_all: false, rules: [] }],
    }))

  // ── 目录选择 ──────────────────────────────────────────────────────────────
  const openDirPicker = (target) => { setDirPickerTarget(target); setDirPickerOpen(true) }
  const handleDirSelected = (path) => {
    if (dirPickerTarget === 'target_root')      setCfg(c => ({ ...c, target_root: path }))
    if (dirPickerTarget === 'unrecognized_dir') setCfg(c => ({ ...c, unrecognized_dir: path }))
  }

  // ── 渲染 ──────────────────────────────────────────────────────────────────
  return (
    <Card
      title={<Space><FolderAddOutlined style={{ color: '#6366f1' }} />整理分类引擎</Space>}
      extra={
        <Space>
          <Segmented
            value={editMode}
            onChange={handleModeChange}
            options={[
              { value: 'gui',  label: <Space size={4}><AppstoreOutlined />图形化</Space> },
              { value: 'code', label: <Space size={4}><CodeOutlined />代码</Space> },
            ]}
          />
          <Button type="primary" icon={<SaveOutlined />} loading={saving} onClick={handleSave}>
            保存配置
          </Button>
        </Space>
      }
    >
      {/* TMDB 状态提示 */}
      {tmdbOk !== null && (
        <Alert
          style={{ marginBottom: 16 }}
          type={tmdbOk ? 'success' : 'warning'}
          showIcon
          message={tmdbOk
            ? '已配置 TMDB API Key，genre_ids / 产地 / 语言规则将生效'
            : '未配置 TMDB API Key，TMDB 类型/产地/语言规则不生效，仅关键词/正则有效'}
        />
      )}

      <Alert type="info" showIcon style={{ marginBottom: 16 }}
        icon={<InfoCircleOutlined />}
        message="分类规则为通用配置，所有整理任务（115监控、手动触发等）都将引用此处的规则进行文件分类。" />

      {editMode === 'code'
        ? (
          <Row gutter={24}>
            <Col xs={24} lg={16}>
              <CodeEditor value={codeText} onChange={setCodeText} />
            </Col>
            <Col xs={24} lg={8}>
              <Card size="small" title="字段说明" style={{ position: 'sticky', top: 24 }}>
                <div style={{ fontSize: 12, lineHeight: 2, color: '#666' }}>
                  <div><b>enabled</b>：是否启用分类引擎</div>
                  <div><b>dry_run</b>：试运行（只记日志，不移动文件）</div>
                  <div><b>target_root</b>：115网盘整理目标根目录</div>
                  <div><b>unrecognized_dir</b>：未识别文件目录</div>
                  <Divider style={{ margin: '8px 0' }} />
                  <div><b>categories[]</b>：分类规则列表，按顺序匹配</div>
                  <div style={{ paddingLeft: 12 }}>
                    <div>• <b>name</b>：分类名</div>
                    <div>• <b>target_dir</b>：目标子目录（相对 target_root）</div>
                    <div>• <b>match_all</b>：true=AND，false=OR</div>
                    <div>• <b>rules[]</b>：空=默认兜底分类</div>
                  </div>
                  <Divider style={{ margin: '8px 0' }} />
                  <div><b>rules[].type</b></div>
                  <div style={{ paddingLeft: 12 }}>
                    <div>• <code>keyword</code> / <code>regex</code></div>
                    <div>• <code>genre_ids</code>（TMDB类型ID）</div>
                    <div>• <code>origin_country</code>（产地）</div>
                    <div>• <code>original_language</code>（语言）</div>
                  </div>
                </div>
              </Card>
            </Col>
          </Row>
        )
        : (
          <Row gutter={24}>
            {/* 左侧：全局设置 */}
            <Col xs={24} lg={8}>
              <Card size="small" title="全局设置" style={{ marginBottom: 16 }}>
                <Form layout="vertical" size="small">
                  <Form.Item label="启用分类引擎">
                    <Switch checked={cfg.enabled}
                      checkedChildren="启用" unCheckedChildren="禁用"
                      onChange={v => setCfg(c => ({ ...c, enabled: v }))} />
                  </Form.Item>
                  <Form.Item label="试运行（只记日志，不实际移动）">
                    <Switch checked={cfg.dry_run}
                      onChange={v => setCfg(c => ({ ...c, dry_run: v }))} />
                  </Form.Item>
                  <Form.Item label="整理目标根目录" tooltip="115网盘路径，如 /整理后">
                    <Input value={cfg.target_root} placeholder="/整理后"
                      onChange={e => setCfg(c => ({ ...c, target_root: e.target.value }))}
                      addonAfter={
                        <Button type="link" size="small" icon={<FolderOpenOutlined />}
                          onClick={() => openDirPicker('target_root')}
                          style={{ padding: 0, height: 'auto' }}>选择</Button>
                      } />
                  </Form.Item>
                  <Form.Item label="未识别文件目录" tooltip="无法命中任何分类的文件移入此处">
                    <Input value={cfg.unrecognized_dir} placeholder="/未识别"
                      onChange={e => setCfg(c => ({ ...c, unrecognized_dir: e.target.value }))}
                      addonAfter={
                        <Button type="link" size="small" icon={<FolderOpenOutlined />}
                          onClick={() => openDirPicker('unrecognized_dir')}
                          style={{ padding: 0, height: 'auto' }}>选择</Button>
                      } />
                  </Form.Item>
                </Form>
              </Card>

              {/* 规则说明 */}
              <Card size="small" title={<Space><InfoCircleOutlined />规则说明</Space>}>
                <div style={{ fontSize: 12, lineHeight: 1.9, color: '#888' }}>
                  <div>• 分类按列表顺序从上到下匹配，命中第一个</div>
                  <div>• 无规则的分类作为「兜底」，排在末尾</div>
                  <div>• OR模式：任一规则满足即命中</div>
                  <div>• AND模式：全部规则都满足才命中</div>
                  <Divider style={{ margin: '6px 0' }} />
                  <div>• <b>关键词/正则</b>：本地匹配，无需TMDB</div>
                  <div>• <b>TMDB类型/产地/语言</b>：需配置TMDB Key</div>
                  <div style={{ marginTop: 4 }}>genre_ids 常用：16=动画 99=纪录片</div>
                </div>
              </Card>
            </Col>

            {/* 右侧：分类规则列表 */}
            <Col xs={24} lg={16}>
              <div style={{ marginBottom: 8, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Space>
                  <Text strong>分类规则</Text>
                  <Badge count={cfg.categories?.length || 0} showZero
                    style={{ backgroundColor: '#6366f1' }} />
                </Space>
                <Text type="secondary" style={{ fontSize: 12 }}>优先级从上到下，上方分类优先匹配</Text>
              </div>

              {(cfg.categories || []).map((cat, idx) => (
                <CategoryCard
                  key={idx}
                  cat={cat}
                  catIdx={idx}
                  total={cfg.categories.length}
                  color={CAT_COLORS[idx % CAT_COLORS.length]}
                  onUpdate={(patch) => updateCat(idx, patch)}
                  onDelete={() => deleteCat(idx)}
                  onMove={(dir) => moveCat(idx, dir)}
                />
              ))}

              <Button block icon={<PlusOutlined />} onClick={addCat}
                style={{ borderStyle: 'dashed', marginTop: 4 }}>
                添加分类
              </Button>
            </Col>
          </Row>
        )
      }

      <DirPickerModal
        open={dirPickerOpen}
        onClose={() => setDirPickerOpen(false)}
        onSelect={(p) => { handleDirSelected(p); setDirPickerOpen(false) }}
      />
    </Card>
  )
}

export default Classify

