  const updateRule = (i, p) => onUpdate({ rules: cat.rules.map((r, ri) => ri === i ? { ...r, ...p } : r) })
  const addRule    = ()     => onUpdate({ rules: [...(cat.rules || []), { type: 'keyword', field: 'filename', value: '' }] })
  const delRule    = (i)    => onUpdate({ rules: cat.rules.filter((_, ri) => ri !== i) })

  return (
    <div style={{
      border: '1px solid var(--ant-color-border,#d9d9d9)',
      borderLeft: `4px solid var(--ant-color-${color}-6,#1677ff)`,
      borderRadius: 8, marginBottom: 12,
      background: 'var(--ant-color-bg-container,#fff)', overflow: 'hidden',
    }}>
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8, padding: '8px 12px',
        background: 'var(--ant-color-fill-quaternary,rgba(0,0,0,.04))',
        borderBottom: '1px solid var(--ant-color-border-secondary,#f0f0f0)',
      }}>
        <span style={{
          width: 22, height: 22, borderRadius: '50%', flexShrink: 0,
          background: `var(--ant-color-${color}-6,#1677ff)`, color: '#fff',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 11, fontWeight: 700,
        }}>{catIdx + 1}</span>

        <Input size="small" variant="borderless" value={cat.name} placeholder="分类名称"
          style={{ fontWeight: 600, flex: 1, maxWidth: 140 }}
          onChange={e => onUpdate({ name: e.target.value })} />
        <Text type="secondary" style={{ fontSize: 12 }}>→</Text>
        <Input size="small" variant="borderless" value={cat.target_dir} placeholder="目标子目录"
          style={{ flex: 1, maxWidth: 160, fontSize: 12 }}
          onChange={e => onUpdate({ target_dir: e.target.value })} />
        {isDefault && <Tag color="orange" style={{ fontSize: 11, margin: 0 }}>默认兜底</Tag>}

        <Space size={2} style={{ flexShrink: 0 }}>
          <Tooltip title="上移"><Button size="small" icon={<ArrowUpOutlined />}
            disabled={catIdx === 0} onClick={() => onMove(-1)} /></Tooltip>
          <Tooltip title="下移"><Button size="small" icon={<ArrowDownOutlined />}
            disabled={catIdx === total - 1} onClick={() => onMove(1)} /></Tooltip>
          <Tooltip title="删除"><Button size="small" danger icon={<DeleteOutlined />}
            onClick={onDelete} /></Tooltip>
        </Space>
      </div>

      <div style={{ padding: '10px 12px' }}>
        {cat.rules?.length > 1 && (
          <div style={{ marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
            <Text type="secondary" style={{ fontSize: 12 }}>匹配逻辑：</Text>
            <Switch size="small" checked={cat.match_all}
              checkedChildren="AND 全部" unCheckedChildren="OR 任一"
              onChange={v => onUpdate({ match_all: v })} />
          </div>
        )}

        {isDefault
          ? <Text type="secondary" style={{ fontSize: 12, fontStyle: 'italic' }}>
              无匹配规则 — 作为兜底分类（未命中其他分类的文件归入此处）
            </Text>
          : (cat.rules || []).map((rule, rIdx) => {
              const isTmdb = TMDB_TYPES.includes(rule.type)
              return (
                <Row key={rIdx} gutter={4} style={{ marginBottom: 6 }} align="middle" wrap={false}>
                  <Col style={{ width: 110, flexShrink: 0 }}>
                    <Select size="small" style={{ width: '100%' }} value={rule.type}
                      options={RULE_TYPE_OPTIONS}
                      onChange={v => updateRule(rIdx, {
                        type: v, field: TMDB_TYPES.includes(v) ? undefined : (rule.field || 'filename'),
                      })} />
                  </Col>
                  {!isTmdb && (
                    <Col style={{ width: 76, flexShrink: 0 }}>
                      <Select size="small" style={{ width: '100%' }} value={rule.field || 'filename'}
                        options={[{ value: 'filename', label: '文件名' }, { value: 'dirname', label: '目录名' }]}
                        onChange={v => updateRule(rIdx, { field: v })} />
                    </Col>
                  )}
                  <Col flex="1">
                    <Tooltip title={RULE_HINTS[rule.type]}>
                      <Input size="small" value={rule.value}
                        placeholder={RULE_HINTS[rule.type] || '输入匹配值'}
                        onChange={e => updateRule(rIdx, { value: e.target.value })} />
                    </Tooltip>
                  </Col>
                  <Col>
                    <Button danger size="small" icon={<DeleteOutlined />}
                      onClick={() => delRule(rIdx)} />
                  </Col>
                </Row>
              )
            })
        }
        <Button size="small" icon={<PlusOutlined />} onClick={addRule}
          style={{ marginTop: isDefault ? 0 : 4 }}>
          添加规则
        </Button>
      </div>
    </div>
  )
}

// ─── 代码编辑器 ──────────────────────────────────────────────────────────────
const CodeEditor = ({ value, onChange }) => {
  const [err, setErr] = useState('')
  const handleChange = (v) => {
    onChange(v)
    try { JSON.parse(v); setErr('') } catch (e) { setErr(e.message) }
  }
  return (
    <div>
      <Alert type="info" showIcon style={{ marginBottom: 8 }}
        message="直接编辑 JSON 配置，保存时将覆盖图形化设置。修改后可切换回图形化模式预览效果。" />
      {err && <Alert type="error" message={`JSON 格式错误: ${err}`} style={{ marginBottom: 8 }} />}
      <TextArea value={value} rows={22} spellCheck={false}
        onChange={e => handleChange(e.target.value)}
        style={{
          fontFamily: "'Cascadia Code','Fira Code',monospace",
          fontSize: 12, lineHeight: 1.6, resize: 'vertical',
        }} />
    </div>
  )
}

// ─── 主页面 ──────────────────────────────────────────────────────────────────
export const Classify = () => {
  const [cfg, setCfg]           = useState(DEFAULT_CONFIG)
  const [editMode, setEditMode] = useState('gui')
  const [codeText, setCodeText] = useState('')
  const [saving, setSaving]     = useState(false)
  const [tmdbOk, setTmdbOk]     = useState(null)
  const [dirOpen, setDirOpen]   = useState(false)
  const [dirTarget, setDirTarget] = useState(null)

  const load = useCallback(async () => {
    try {
      const [cfgRes, tmdbRes] = await Promise.all([
        classifyApi.getConfig(),
        classifyApi.getTmdbStatus(),
      ])
      const data = cfgRes.data || DEFAULT_CONFIG
      setCfg(data)
      setCodeText(JSON.stringify(data, null, 2))
      setTmdbOk(!!tmdbRes.data?.available)
    } catch { message.error('加载分类配置失败') }
  }, [])

  useEffect(() => { load() }, [load])

  const handleModeChange = (mode) => {
    if (mode === 'code') {
      setCodeText(JSON.stringify(cfg, null, 2))
    } else {
      try { setCfg(JSON.parse(codeText)) }
      catch { message.warning('JSON 格式错误，保留当前图形化状态') }
    }
    setEditMode(mode)
  }

  const handleSave = async () => {
    let payload = cfg
    if (editMode === 'code') {
      try { payload = JSON.parse(codeText) }
      catch { message.error('JSON 格式错误，无法保存'); return }
    }
    setSaving(true)
    try {
      await classifyApi.saveConfig(payload)
      setCfg(payload)
      setCodeText(JSON.stringify(payload, null, 2))
      message.success('分类配置已保存')
    } catch { message.error('保存失败') }
    finally { setSaving(false) }
  }

  const updateCat = (i, p) =>
    setCfg(c => ({ ...c, categories: c.categories.map((v, ci) => ci === i ? { ...v, ...p } : v) }))
  const deleteCat = (i) =>
    setCfg(c => ({ ...c, categories: c.categories.filter((_, ci) => ci !== i) }))
  const moveCat   = (i, dir) =>
    setCfg(c => {
      const arr = [...c.categories]
      ;[arr[i], arr[i + dir]] = [arr[i + dir], arr[i]]
      return { ...c, categories: arr }
    })
  const addCat = () =>
    setCfg(c => ({ ...c, categories: [...c.categories, { name: '', target_dir: '', match_all: false, rules: [] }] }))

  const openDir  = (t) => { setDirTarget(t); setDirOpen(true) }
  const onDirSel = (path) => {
    if (dirTarget === 'target_root')      setCfg(c => ({ ...c, target_root: path }))
    if (dirTarget === 'unrecognized_dir') setCfg(c => ({ ...c, unrecognized_dir: path }))
  }

  return (
    <Card
      title={<Space><FolderAddOutlined style={{ color: '#6366f1' }} />整理分类引擎</Space>}
      extra={
        <Space>
          <Segmented value={editMode} onChange={handleModeChange}
            options={[
              { value: 'gui',  label: <Space size={4}><AppstoreOutlined />图形化</Space> },
              { value: 'code', label: <Space size={4}><CodeOutlined />代码</Space> },
            ]} />
          <Button type="primary" icon={<SaveOutlined />} loading={saving} onClick={handleSave}>
            保存配置
          </Button>
        </Space>
      }
    >
      {tmdbOk !== null && (
        <Alert style={{ marginBottom: 16 }}
          type={tmdbOk ? 'success' : 'warning'} showIcon
          message={tmdbOk
            ? '已配置 TMDB API Key，TMDB 类型 / 产地 / 语言规则生效'
            : '未配置 TMDB API Key，TMDB 规则不生效，仅关键词 / 正则有效'} />
      )}

      <Alert type="info" showIcon style={{ marginBottom: 16 }} icon={<InfoCircleOutlined />}
        message="分类规则为通用配置，所有整理任务（115 监控、手动触发等）引用此处规则进行文件分类，与具体路径无关。" />

      {editMode === 'code'
        ? (
          <Row gutter={24}>
            <Col xs={24} lg={17}><CodeEditor value={codeText} onChange={setCodeText} /></Col>
            <Col xs={24} lg={7}>
              <Card size="small" title="字段说明" style={{ position: 'sticky', top: 24 }}>
                <div style={{ fontSize: 12, lineHeight: 2, color: '#666' }}>
                  <div><b>enabled</b>：启用分类引擎</div>
                  <div><b>dry_run</b>：试运行（不移动文件）</div>
                  <div><b>target_root</b>：整理目标根目录</div>
                  <div><b>unrecognized_dir</b>：未识别文件目录</div>
                  <Divider style={{ margin: '6px 0' }} />
                  <div><b>categories[]</b>：按序匹配，先匹配先命中</div>
                  <div style={{ paddingLeft: 12 }}>
                    <div>• name / target_dir / match_all</div>
                    <div>• rules[]：空 = 兜底分类</div>
                  </div>
                  <Divider style={{ margin: '6px 0' }} />
                  <div><b>rules[].type：</b></div>
                  <div style={{ paddingLeft: 12 }}>
                    <div>keyword / regex（本地）</div>
                    <div>genre_ids（TMDB类型，如 16）</div>
                    <div>origin_country（如 JP）</div>
                    <div>original_language（如 ja）</div>
                  </div>
                </div>
              </Card>
            </Col>
          </Row>
        )
        : (
          <Row gutter={24}>
            <Col xs={24} lg={8}>
              <Card size="small" title="全局设置" style={{ marginBottom: 16 }}>
                <Form layout="vertical" size="small">
                  <Form.Item label="启用分类引擎">
                    <Switch checked={cfg.enabled} checkedChildren="启用" unCheckedChildren="禁用"
                      onChange={v => setCfg(c => ({ ...c, enabled: v }))} />
                  </Form.Item>
                  <Form.Item label="试运行（只记日志，不实际移动）">
                    <Switch checked={cfg.dry_run}
                      onChange={v => setCfg(c => ({ ...c, dry_run: v }))} />
                  </Form.Item>
                  <Form.Item label="整理目标根目录" tooltip="115 网盘路径，如 /整理后">
                    <Input value={cfg.target_root} placeholder="/整理后"
                      onChange={e => setCfg(c => ({ ...c, target_root: e.target.value }))}
                      suffix={<Button type="link" size="small" icon={<FolderOpenOutlined />}
                        style={{ padding: 0 }} onClick={() => openDir('target_root')} />} />
                  </Form.Item>
                  <Form.Item label="未识别文件目录" tooltip="无法命中任何分类的文件移入此处">
                    <Input value={cfg.unrecognized_dir} placeholder="/未识别"
                      onChange={e => setCfg(c => ({ ...c, unrecognized_dir: e.target.value }))}
                      suffix={<Button type="link" size="small" icon={<FolderOpenOutlined />}
                        style={{ padding: 0 }} onClick={() => openDir('unrecognized_dir')} />} />
                  </Form.Item>
                </Form>
              </Card>

              <Card size="small" title={<Space><InfoCircleOutlined />规则说明</Space>}>
                <div style={{ fontSize: 12, lineHeight: 1.9, color: '#888' }}>
                  <div>• 从上到下顺序匹配，命中第一个即归类</div>
                  <div>• 无规则的分类作为「兜底」，建议放最后</div>
                  <div>• <b>OR</b>：任一规则满足即命中</div>
                  <div>• <b>AND</b>：全部规则都满足才命中</div>
                  <Divider style={{ margin: '6px 0' }} />
                  <div>• 关键词 / 正则：仅本地匹配，无需 TMDB</div>
                  <div>• TMDB 规则：需在系统设置中配置 API Key</div>
                  <div style={{ marginTop: 4 }}>
                    TMDB genre_ids：16=动画 99=纪录片<br />
                    origin_country：JP CN TW HK US<br />
                    original_language：ja zh en ko
                  </div>
                </div>
              </Card>
            </Col>

            <Col xs={24} lg={16}>
              <div style={{ marginBottom: 10, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Space>
                  <Text strong>分类规则列表</Text>
                  <Badge count={cfg.categories?.length || 0} showZero
                    style={{ backgroundColor: '#6366f1' }} />
                </Space>
                <Text type="secondary" style={{ fontSize: 12 }}>优先级从上到下，上方分类优先匹配</Text>
              </div>

              {(cfg.categories || []).map((cat, idx) => (
                <CategoryCard key={idx} cat={cat} catIdx={idx}
                  total={cfg.categories.length}
                  color={CAT_COLORS[idx % CAT_COLORS.length]}
                  onUpdate={(p) => updateCat(idx, p)}
                  onDelete={() => deleteCat(idx)}
                  onMove={(dir) => moveCat(idx, dir)} />
              ))}

              <Button block icon={<PlusOutlined />} onClick={addCat}
                style={{ borderStyle: 'dashed', marginTop: 4 }}>
                添加分类
              </Button>
            </Col>
          </Row>
        )
      }

      <DirPickerModal open={dirOpen}
        onClose={() => setDirOpen(false)}
        onSelect={(p) => { onDirSel(p); setDirOpen(false) }} />
    </Card>
  )
}

