// 通用整理分类模块 — 独立页面
// 职责：管理分类规则配置，不绑定任何具体平台（115/本地等）
// 其他模块触发整理时读取此配置进行分类。

import { useEffect, useState, useRef, useCallback } from 'react'
import {
  Card, Row, Col, Form, Input, Switch, Button, Select, Tag, Space,
  Alert, Tooltip, Divider, message, Segmented, Badge, Typography,
} from 'antd'
import {
  FolderAddOutlined, PlusOutlined, DeleteOutlined, SaveOutlined,
  ArrowUpOutlined, ArrowDownOutlined, CodeOutlined, AppstoreOutlined,
  CheckCircleOutlined, InfoCircleOutlined, FolderOpenOutlined,
} from '@ant-design/icons'
import { classifyApi } from '@/apis'
import DirPickerModal from '@/components/DirPickerModal'

const { Text } = Typography
const { TextArea } = Input

// 分类卡片颜色序列
const CAT_COLORS = ['blue','purple','green','orange','red','cyan','volcano','gold','lime','magenta']

// 规则类型选项
const RULE_TYPE_OPTIONS = [
  { value: 'keyword',           label: '关键词' },
  { value: 'regex',             label: '正则' },
  { value: 'genre_ids',         label: 'TMDB类型ID' },
  { value: 'origin_country',    label: 'TMDB产地' },
  { value: 'original_language', label: 'TMDB语言' },
]
const TMDB_TYPES = ['genre_ids', 'origin_country', 'original_language']

const RULE_HINTS = {
  genre_ids:         'TMDB genre_id，多个逗号分隔，如 16（动画）、99（纪录片）',
  origin_country:    '国家代码，多个逗号分隔，如 JP 或 CN,TW,HK',
  original_language: 'TMDB original_language，如 zh、ja、en',
  keyword:           '文件名/目录名中包含的关键词',
  regex:             '正则表达式，如 (?i)(anime|OVA)',
}

const DEFAULT_CONFIG = {
  enabled: true,
  dry_run: false,
  target_root: '',
  unrecognized_dir: '',
  categories: [],
}

// ─── 单个分类卡片 ──────────────────────────────────────────────────────────────
const CategoryCard = ({ cat, catIdx, total, onUpdate, onDelete, onMove, color }) => {
  const isDefault = !cat.rules || cat.rules.length === 0

  const updateRule = (rIdx, patch) =>
    onUpdate({ rules: cat.rules.map((r, i) => i === rIdx ? { ...r, ...patch } : r) })
  const addRule = () =>
    onUpdate({ rules: [...(cat.rules || []), { type: 'keyword', field: 'filename', value: '' }] })
  const delRule = (rIdx) =>
    onUpdate({ rules: cat.rules.filter((_, i) => i !== rIdx) })

  return (
    <div style={{
      border: '1px solid var(--ant-color-border, #d9d9d9)',
      borderLeft: `4px solid var(--ant-color-${color}-6, #1677ff)`,
      borderRadius: 8, marginBottom: 12, background: 'var(--ant-color-bg-container,#fff)',
      overflow: 'hidden',
    }}>
      {/* 卡片头 */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8, padding: '8px 12px',
        background: 'var(--ant-color-fill-quaternary, rgba(0,0,0,.04))',
        borderBottom: '1px solid var(--ant-color-border-secondary, #f0f0f0)',
      }}>
        <span style={{
          width: 22, height: 22, borderRadius: '50%', flexShrink: 0,
          background: `var(--ant-color-${color}-6, #1677ff)`, color: '#fff',
          display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, fontWeight: 700,
        }}>{catIdx + 1}</span>

        <Input
          size="small" variant="borderless"
          value={cat.name} placeholder="分类名称"
          style={{ fontWeight: 600, flex: 1, maxWidth: 140 }}
          onChange={e => onUpdate({ name: e.target.value })}
        />
        <Text type="secondary" style={{ fontSize: 12 }}>→</Text>
        <Input
          size="small" variant="borderless"
          value={cat.target_dir} placeholder="目标子目录"
          style={{ flex: 1, maxWidth: 160, fontSize: 12 }}
          onChange={e => onUpdate({ target_dir: e.target.value })}
        />

        {isDefault && <Tag color="orange" style={{ fontSize: 11, margin: 0 }}>默认兜底</Tag>}

        <Space size={2} style={{ flexShrink: 0 }}>
          <Tooltip title="上移"><Button size="small" icon={<ArrowUpOutlined />} disabled={catIdx === 0}
            onClick={() => onMove(-1)} /></Tooltip>
          <Tooltip title="下移"><Button size="small" icon={<ArrowDownOutlined />} disabled={catIdx === total - 1}
            onClick={() => onMove(1)} /></Tooltip>
          <Tooltip title="删除分类"><Button size="small" danger icon={<DeleteOutlined />} onClick={onDelete} /></Tooltip>
        </Space>
      </div>

      {/* 规则区域 */}
      <div style={{ padding: '10px 12px' }}>
        {/* 匹配逻辑 */}
        {cat.rules?.length > 1 && (
          <div style={{ marginBottom: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
            <Text type="secondary" style={{ fontSize: 12 }}>匹配逻辑：</Text>
            <Switch size="small" checked={cat.match_all}
              checkedChildren="AND 全部" unCheckedChildren="OR 任一"
              onChange={v => onUpdate({ match_all: v })} />
          </div>
        )}

        {isDefault
          ? <Text type="secondary" style={{ fontSize: 12, fontStyle: 'italic' }}>
              无匹配规则 — 作为兜底分类（未命中其他分类的文件归入此处）
            </Text>
          : (cat.rules || []).map((rule, rIdx) => {
            const isTmdb = TMDB_TYPES.includes(rule.type)
            return (
              <Row key={rIdx} gutter={4} style={{ marginBottom: 6 }} align="middle" wrap={false}>
                <Col style={{ width: 110, flexShrink: 0 }}>
                  <Select size="small" style={{ width: '100%' }} value={rule.type}
                    options={RULE_TYPE_OPTIONS}
                    onChange={v => updateRule(rIdx, {
                      type: v,
                      field: TMDB_TYPES.includes(v) ? undefined : (rule.field || 'filename'),
                    })} />
                </Col>
                {!isTmdb && (
                  <Col style={{ width: 76, flexShrink: 0 }}>
                    <Select size="small" style={{ width: '100%' }} value={rule.field || 'filename'}
                      options={[{ value: 'filename', label: '文件名' }, { value: 'dirname', label: '目录名' }]}
                      onChange={v => updateRule(rIdx, { field: v })} />
                  </Col>
                )}
                <Col flex="1">
                  <Tooltip title={RULE_HINTS[rule.type]}>
                    <Input size="small" value={rule.value}
                      placeholder={RULE_HINTS[rule.type] || '输入匹配值'}
                      onChange={e => updateRule(rIdx, { value: e.target.value })} />
                  </Tooltip>
                </Col>
                <Col>
                  <Button danger size="small" icon={<DeleteOutlined />} onClick={() => delRule(rIdx)} />
                </Col>
              </Row>
            )
          })
        }

        <Button size="small" icon={<PlusOutlined />} onClick={addRule}
          style={{ marginTop: isDefault ? 0 : 4 }}>
          添加规则
        </Button>
      </div>
    </div>
  )
}

// ─── 代码编辑模式 ──────────────────────────────────────────────────────────────
const CodeEditor = ({ value, onChange }) => {
  const [err, setErr] = useState('')
  const handleChange = (v) => {
    onChange(v)
    try { JSON.parse(v); setErr('') } catch (e) { setErr(e.message) }
  }
  return (
    <div>
      <Alert type="info" showIcon style={{ marginBottom: 8 }}
        message="直接编辑 JSON 配置，保存时将覆盖图形化设置。修改后切换到图形化模式可预览效果。" />
      {err && <Alert type="error" message={`JSON 格式错误: ${err}`} style={{ marginBottom: 8 }} />}
      <TextArea
        value={value} rows={20} spellCheck={false}
        onChange={e => handleChange(e.target.value)}
        style={{
          fontFamily: "'Cascadia Code','Fira Code',monospace", fontSize: 12,
          lineHeight: 1.6, resize: 'vertical',
          background: 'var(--ant-color-bg-container,#fff)',
        }}
      />
    </div>
  )
}
"}

