const CategoryCard = ({ cat, catIdx, total, color, onUpdate, onDelete, onMove }) => {
  const isDefault = !cat.rules || cat.rules.length === 0
  const updateRule = (i, p) => onUpdate({ rules: cat.rules.map((r, ri) => ri === i ? { ...r, ...p } : r) })
  const addRule    = ()     => onUpdate({ rules: [...(cat.rules || []), { type: 'keyword', field: 'filename', value: '' }] })
