const CodeEditor = ({ value, onChange }) => {
  const [err, setErr] = useState('')
  const handleChange = (v) => {
    onChange(v)
    try { JSON.parse(v); setErr('') } catch (e) { setErr(e.message) }
  }
  return (
    <div>
      <Alert type="info" showIcon style={{ marginBottom: 8 }}
        message="直接编辑 JSON 配置，保存时将覆盖图形化设置。修改后可切换回图形化模式预览效果。" />
      {err && <Alert type="error" message={`JSON 格式错误: ${err}`} style={{ marginBottom: 8 }} />}
      <TextArea value={value} rows={22} spellCheck={false}
        onChange={e => handleChange(e.target.value)}
        style={{
          fontFamily: "'Cascadia Code','Fira Code',monospace",
          fontSize: 12, lineHeight: 1.6, resize: 'vertical',
        }} />
    </div>
  )
}

