                  </Form.Item>
                  <Form.Item label="未识别文件目录" tooltip="无法命中任何分类的文件移入此处">
                    <Input value={cfg.unrecognized_dir} placeholder="/未识别"
                      onChange={e => setCfg(c => ({ ...c, unrecognized_dir: e.target.value }))}
                      suffix={<Button type="link" size="small" icon={<FolderOpenOutlined />}
                        style={{ padding: 0 }} onClick={() => openDir('unrecognized_dir')} />} />
                  </Form.Item>
                </Form>
              </Card>

              <Card size="small" title={<Space><InfoCircleOutlined />规则说明</Space>}>
                <div style={{ fontSize: 12, lineHeight: 1.9, color: '#888' }}>
                  <div>• 从上到下顺序匹配，命中第一个即归类</div>
                  <div>• 无规则的分类作为「兜底」，建议放最后</div>
                  <div>• <b>OR</b>：任一规则满足即命中</div>
                  <div>• <b>AND</b>：全部规则都满足才命中</div>
                  <Divider style={{ margin: '6px 0' }} />
                  <div>• 关键词 / 正则：仅本地匹配，无需 TMDB</div>
                  <div>• TMDB 规则：需在系统设置中配置 API Key</div>
                  <div style={{ marginTop: 4 }}>
                    TMDB genre_ids：16=动画 99=纪录片<br />
                    origin_country：JP CN TW HK US<br />
                    original_language：ja zh en ko
                  </div>
                </div>
              </Card>
            </Col>

            <Col xs={24} lg={16}>
              <div style={{ marginBottom: 10, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Space>
                  <Text strong>分类规则列表</Text>
                  <Badge count={cfg.categories?.length || 0} showZero
                    style={{ backgroundColor: '#6366f1' }} />
                </Space>
                <Text type="secondary" style={{ fontSize: 12 }}>优先级从上到下，上方分类优先匹配</Text>
              </div>

              {(cfg.categories || []).map((cat, idx) => (
                <CategoryCard key={idx} cat={cat} catIdx={idx}
                  total={cfg.categories.length}
                  color={CAT_COLORS[idx % CAT_COLORS.length]}
                  onUpdate={(p) => updateCat(idx, p)}
                  onDelete={() => deleteCat(idx)}
                  onMove={(dir) => moveCat(idx, dir)} />
              ))}

              <Button block icon={<PlusOutlined />} onClick={addCat}
                style={{ borderStyle: 'dashed', marginTop: 4 }}>
                添加分类
              </Button>
            </Col>
          </Row>
        )
      }

      <DirPickerModal open={dirOpen}
        onClose={() => setDirOpen(false)}
        onSelect={(p) => { onDirSel(p); setDirOpen(false) }} />
    </Card>
  )
}

