} from '@ant-design/icons'
import { classifyApi } from '@/apis'
import DirPickerModal from '@/components/DirPickerModal'

const { Text } = Typography
const { TextArea } = Input

// ─── 默认配置 ─────────────────────────────────────────────────────────────────
const DEFAULT_CONFIG = {
  enabled: true,
  dry_run: false,
  target_root: '',
  unrecognized_dir: '',
  categories: [],
}

