]

// ─── 规则类型分组 ─────────────────────────────────────────────────────────────
const RULE_TYPE_GROUPS = [
  {
    label: '本地匹配',
    options: [
      { value: 'keyword', label: '关键词' },
      { value: 'regex',   label: '正则表达式' },
    ],
  },
  {
    label: '元数据匹配',
    options: [
      { value: 'genre_ids',          label: 'TMDB 类型 ID' },
      { value: 'origin_country',     label: '产地代码' },
      { value: 'original_language',  label: '原始语言' },
    ],
  },
]

const FIELD_OPTIONS = [
  { value: 'filename', label: '文件名' },
  { value: 'dirname',  label: '目录名' },
]

const LOCAL_RULE_TYPES = ['keyword', 'regex']

// ─── 单条规则行 ───────────────────────────────────────────────────────────────
const RuleRow = ({ rule, onChange, onDelete }) => {
  const needsField = LOCAL_RULE_TYPES.includes(rule.type)
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 6,
      padding: '5px 0',
    }}>
      {/* 类型 */}
      <Select
        size="small"
        value={rule.type}
        style={{ width: 130, flexShrink: 0 }}
        options={RULE_TYPE_GROUPS}
        onChange={v => onChange({ ...rule, type: v, field: LOCAL_RULE_TYPES.includes(v) ? (rule.field || 'filename') : undefined })}
      />
      {/* 字段（仅本地匹配需要） */}
      {needsField ? (
        <Select
          size="small"
          value={rule.field || 'filename'}
          style={{ width: 90, flexShrink: 0 }}
          options={FIELD_OPTIONS}
          onChange={v => onChange({ ...rule, field: v })}
        />
      ) : (
        <div style={{ width: 90, flexShrink: 0 }} />
      )}
      {/* 值 */}
      <Input
        size="small"
        value={rule.value}
        placeholder={rule.type === 'genre_ids' ? '如：16（动画）' : rule.type === 'origin_country' ? '如：JP' : rule.type === 'original_language' ? '如：ja' : '匹配值'}
        style={{ flex: 1 }}
        onChange={e => onChange({ ...rule, value: e.target.value })}
      />
      <Button size="small" type="text" danger icon={<DeleteOutlined />} onClick={onDelete} />
    </div>
  )
}

// ─── 分类卡片（一级） ─────────────────────────────────────────────────────────
const CategoryCard = ({ cat, idx, total, color, onUpdate, onDelete, onMove }) => {
  const rules = cat.rules || []
  const isDefault = rules.length === 0

  const addRule = () => onUpdate({
    rules: [...rules, { type: 'keyword', field: 'filename', value: '' }],
  })
  const updateRule = (ri, r) => onUpdate({ rules: rules.map((x, i) => i === ri ? r : x) })
  const deleteRule = (ri) => onUpdate({ rules: rules.filter((_, i) => i !== ri) })

  return (
    <div style={{
      borderRadius: 10,
      border: '1px solid var(--ant-color-border, #e5e7eb)',
      marginBottom: 10,
      overflow: 'hidden',
      background: 'var(--ant-color-bg-container, #fff)',
      boxShadow: '0 1px 4px rgba(0,0,0,.06)',
    }}>
      {/* ── 卡片头部 ── */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8,
        padding: '9px 12px',
        borderLeft: `4px solid ${color}`,
        background: 'var(--ant-color-fill-quaternary, rgba(0,0,0,.02))',
        borderBottom: '1px solid var(--ant-color-border-secondary, #f0f0f0)',
      }}>
        {/* 序号圆标 */}
        <div style={{
          width: 22, height: 22, borderRadius: '50%',
          background: color, color: '#fff',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 11, fontWeight: 700, flexShrink: 0,
        }}>{idx + 1}</div>

        {/* 分类名 */}
        <Input
          variant="borderless" size="small"
          value={cat.name} placeholder="分类名称（如：动漫）"
          style={{ fontWeight: 600, fontSize: 13, flex: '0 0 140px', padding: '0 4px' }}
          onChange={e => onUpdate({ name: e.target.value })}
        />

        <Text type="secondary" style={{ fontSize: 12, flexShrink: 0 }}>→</Text>

        {/* 目标子目录 */}
        <Input
          variant="borderless" size="small"
          value={cat.target_dir} placeholder="目标子目录（相对于根目录）"
          style={{ flex: 1, fontSize: 12, color: '#888', padding: '0 4px' }}
          onChange={e => onUpdate({ target_dir: e.target.value })}
        />

        {/* 标签 */}
        {isDefault && <Tag color="orange" style={{ fontSize: 11, flexShrink: 0 }}>兜底</Tag>}
        <Tag style={{ fontSize: 11, flexShrink: 0, color: '#888', borderColor: '#d9d9d9' }}>
          {rules.length} 条规则
        </Tag>

        {/* 匹配模式 */}
        <Tooltip title="规则间逻辑">
          <Select
            size="small" variant="borderless"
            value={cat.match_all ? 'all' : 'any'}
            style={{ width: 70, flexShrink: 0, fontSize: 12 }}
            options={[{ value: 'any', label: '任一' }, { value: 'all', label: '全部' }]}
            onChange={v => onUpdate({ match_all: v === 'all' })}
          />
        </Tooltip>

        {/* 操作 */}
        <Space size={2} style={{ flexShrink: 0 }}>
          <Tooltip title="上移"><Button size="small" type="text" icon={<ArrowUpOutlined />} disabled={idx === 0} onClick={() => onMove(-1)} /></Tooltip>
          <Tooltip title="下移"><Button size="small" type="text" icon={<ArrowDownOutlined />} disabled={idx === total - 1} onClick={() => onMove(1)} /></Tooltip>
          <Tooltip title="删除分类"><Button size="small" type="text" danger icon={<DeleteOutlined />} onClick={onDelete} /></Tooltip>
        </Space>
      </div>

      {/* ── 规则列表 ── */}
      <div style={{ padding: '8px 12px 6px' }}>
        {isDefault ? (
          <div style={{
            padding: '8px 12px', borderRadius: 6, fontSize: 12,
            color: '#b45309', background: 'rgba(251,191,36,.08)',
            border: '1px dashed #fbbf24',
          }}>
            ⚡ 兜底分类：无规则时匹配所有未归类文件，建议放在列表最末。
          </div>
        ) : (
          <>
            {/* 表头 */}
            <div style={{ display: 'flex', gap: 6, padding: '2px 0 4px', fontSize: 11, color: '#aaa' }}>
              <div style={{ width: 130 }}>规则类型</div>
              <div style={{ width: 90 }}>字段</div>
              <div style={{ flex: 1 }}>匹配值</div>
              <div style={{ width: 32 }} />
            </div>
            {rules.map((r, ri) => (
              <RuleRow key={ri} rule={r}
                onChange={nr => updateRule(ri, nr)}
                onDelete={() => deleteRule(ri)}
              />
            ))}
          </>
        )}
        <Button
          size="small" type="dashed" icon={<PlusOutlined />}
          style={{ marginTop: 6, width: '100%', fontSize: 12 }}
          onClick={addRule}
        >添加规则</Button>
      </div>
    </div>
  )
}
"}

