// =============================================================================
// 自定义代码格式解析器
// 格式示例:
//   [动漫]
//   target_dir = 动漫
//   media_type = all
//   genre_ids  = 16, 10762
//   country    = JP
//   language   = ja
//   keyword    = 动漫, 动画, 番剧
